@* Step indicator bar showing progress through the multi-step form *@

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="d-flex list-unstyled justify-content-between position-relative step-list">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var isCurrent = stepIndex == CurrentStep;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isFuture = !isCurrent && !isCompleted;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                @onclick="() => OnStepClick(stepIndex)"
                role="button"
                tabindex="@(isCompleted ? 0 : -1)"
                aria-current="@(isCurrent ? "step" : null)">
                <div class="step-circle mx-auto mb-1 @(isCurrent ? "bg-primary text-white" : "") @(isCompleted ? "bg-success text-white" : "") @(isFuture ? "bg-light text-muted border" : "")">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </div>
                <small class="@(isFuture ? "text-muted" : "") @(isCurrent ? "fw-bold" : "")">@StepNames[stepIndex]</small>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private async Task OnStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

@* A single work entry card within the Work History step *@

<div class="card mb-3 p-3">
    <div class="d-flex justify-content-between align-items-center mb-2">
        <h6 class="mb-0">Position @(Index + 1)</h6>
        @if (CanRemove)
        {
            <button class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
        }
    </div>

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Company <span class="text-danger">*</span></label>
            <input class="form-control @ValidationClass(Company)" @bind="Company" @bind:event="oninput" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Job Title <span class="text-danger">*</span></label>
            <input class="form-control @ValidationClass(Title)" @bind="Title" @bind:event="oninput" />
        </div>
        <div class="col-md-4">
            <label class="form-label">Start Date <span class="text-danger">*</span></label>
            <input type="date" class="form-control @(Attempted && StartDate == default ? "is-invalid" : "")"
                   @bind="StartDate" />
        </div>
        <div class="col-md-4">
            <label class="form-label">End Date</label>
            <input type="date" class="form-control" @bind="EndDate" disabled="@IsCurrent" />
        </div>
        <div class="col-md-4 d-flex align-items-end">
            <div class="form-check mb-2">
                <input class="form-check-input" type="checkbox" id="current-@Index" @bind="IsCurrent" />
                <label class="form-check-label" for="current-@Index">Currently working here</label>
            </div>
        </div>
        <div class="col-12">
            <label class="form-label">Description <span class="text-danger">*</span></label>
            <textarea class="form-control @ValidationClass(Description)" rows="3"
                      @bind="Description" @bind:event="oninput"></textarea>
        </div>
    </div>
</div>

@using sv_c1b04053b23b4f3d92d1b7ce0747b936.Models

@code {
    [Parameter] public int Index { get; set; }
    [Parameter] public string Company { get; set; } = "";
    [Parameter] public string Title { get; set; } = "";
    [Parameter] public DateTime StartDate { get; set; }
    [Parameter] public DateTime? EndDate { get; set; }
    [Parameter] public bool IsCurrent { get; set; }
    [Parameter] public string Description { get; set; } = "";
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public bool Attempted { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
    [Parameter] public EventCallback<WorkEntryData> OnChanged { get; set; }

    public record WorkEntryData(string Company, string Title, DateTime StartDate, DateTime? EndDate, bool IsCurrent, string Description);

    protected override void OnAfterRender(bool firstRender)
    {
        // Notify parent of changes
    }

    private string ValidationClass(string value) =>
        Attempted && string.IsNullOrWhiteSpace(value) ? "is-invalid" : "";

    // Two-way flow: when fields change, notify parent
    private void NotifyChanged()
    {
        OnChanged.InvokeAsync(new WorkEntryData(Company, Title, StartDate, IsCurrent ? null : EndDate, IsCurrent, Description));
    }
}

@* A single reference card *@

<div class="card mb-3 p-3">
    <div class="d-flex justify-content-between align-items-center mb-2">
        <h6 class="mb-0">Reference @(Index + 1)</h6>
