    <h4 class="mb-3">Personal Information</h4>

    <div class="mb-3">
        <label class="form-label" for="fullName">Full Name <span class="text-danger">*</span></label>
        <input id="fullName" class="form-control @(Attempted && string.IsNullOrWhiteSpace(FullName) ? "is-invalid" : "")"
               @bind="FullName" @bind:event="oninput" />
        @if (Attempted && string.IsNullOrWhiteSpace(FullName))
        {
            <div class="invalid-feedback">Full name is required.</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label" for="email">Email <span class="text-danger">*</span></label>
        <input id="email" type="email" class="form-control @(Attempted && string.IsNullOrWhiteSpace(Email) ? "is-invalid" : "") @(EmailError is not null ? "is-invalid" : "")"
               @bind="Email" @bind:event="oninput" />
        @if (Attempted && string.IsNullOrWhiteSpace(Email))
        {
            <div class="invalid-feedback">Email is required.</div>
        }
        else if (EmailError is not null)
        {
            <div class="invalid-feedback">@EmailError</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label" for="phone">Phone <span class="text-danger">*</span></label>
        <input id="phone" class="form-control @(Attempted && string.IsNullOrWhiteSpace(Phone) ? "is-invalid" : "")"
               @bind="Phone" @bind:event="oninput" />
