        <textarea id="address" class="form-control @(Attempted && string.IsNullOrWhiteSpace(Address) ? "is-invalid" : "")"
                  rows="2" @bind="Address" @bind:event="oninput"></textarea>
        @if (Attempted && string.IsNullOrWhiteSpace(Address))
        {
            <div class="invalid-feedback">Address is required.</div>
        }
    </div>

    <div class="d-flex justify-content-end">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
            @if (IsValidating)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Next
        </button>
    </div>
</div>

