@using sv_c1b04053b23b4f3d92d1b7ce0747b936.Services
@inject IApplicationService ApplicationService

<div class="card p-4">
    @if (Submitted)
    {
        <div class="text-center py-5">
            <div class="text-success mb-3" style="font-size: 3rem;">&#10003;</div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@ApplicationId</strong></p>
            <p class="text-muted">Thank you for applying. We will review your application and get back to you.</p>
        </div>
    }
    else
    {
        <h4 class="mb-4">Review Your Application</h4>

        @if (SubmitError is not null)
        {
            <div class="alert alert-danger">@SubmitError</div>
        }

        @* Personal Info *@
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h5>Personal Information</h5>
                <button class="btn btn-link btn-sm" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
            </div>
            <hr class="mt-1" />
            @if (Personal is not null)
            {
                <div class="row">
                    <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                    <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                    <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                    <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
                </div>
            }
        </div>

        @* Work History *@
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h5>Work History</h5>
                <button class="btn btn-link btn-sm" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
            </div>
            <hr class="mt-1" />
            @if (WorkEntries is not null)
            {
                @foreach (var entry in WorkEntries)
                {
                    <div class="mb-3 ps-3 border-start border-3">
                        <div><strong>@entry.Title</strong> at @entry.Company</div>
                        <div class="text-muted">
                            @entry.StartDate.ToString("MMM yyyy") –
                            @(entry.EndDate.HasValue ? entry.EndDate.Value.ToString("MMM yyyy") : "Present")
                        </div>
                        <div>@entry.Description</div>
                    </div>
                }
            }
        </div>

        @* References *@
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h5>References</h5>
                <button class="btn btn-link btn-sm" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
            </div>
            <hr class="mt-1" />
            @if (References is not null)
            {
                @foreach (var r in References)
                {
                    <div class="mb-2 ps-3 border-start border-3">
                        <div><strong>@r.Name</strong> (@r.Relationship)</div>
                        <div class="text-muted">@r.Email · @r.Phone</div>
                    </div>
                }
            }
        </div>

        @* Cover Letter *@
        <div class="mb-4">
            <div class="d-flex justify-content-between align-items-center">
                <h5>Cover Letter</h5>
                <button class="btn btn-link btn-sm" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
            </div>
            <hr class="mt-1" />
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>

        <div class="d-flex justify-content-between">
            <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
            <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @if (IsSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Submit Application
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public PersonalInfo? Personal { get; set; }
    [Parameter] public List<WorkEntry>? WorkEntries { get; set; }
    [Parameter] public List<Reference>? References { get; set; }
    [Parameter] public string? CoverLetter { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private bool IsSubmitting;
    private bool Submitted;
    private int ApplicationId;
    private string? SubmitError;

    private async Task HandleSubmit()
    {
        if (Personal is null || WorkEntries is null || References is null || CoverLetter is null)
            return;

        IsSubmitting = true;
        SubmitError = null;

        try
        {
            var application = new JobApplication(
                Personal,
                new WorkHistory(WorkEntries),
                References,
                CoverLetter
            );

            ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            Submitted = true;
        }
        catch (Exception ex)
        {
            SubmitError = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

