@code {
    [Parameter] public List<WorkEntryModel>? InitialEntries { get; set; }
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryModel>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private List<WorkEntryModel> Entries = new();
    private bool Attempted;

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    protected override void OnInitialized()
    {
        if (InitialEntries is { Count: > 0 })
        {
            Entries = InitialEntries.Select(e => new WorkEntryModel
            {
                Company = e.Company,
                Title = e.Title,
                StartDate = e.StartDate,
                EndDate = e.EndDate,
                IsCurrent = e.IsCurrent,
                Description = e.Description
            }).ToList();
        }
        else
        {
            Entries.Add(new WorkEntryModel());
        }
    }

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private void UpdateEntry(int index, WorkEntryForm.WorkEntryData data)
    {
        if (index < Entries.Count)
        {
            var e = Entries[index];
            e.Company = data.Company;
            e.Title = data.Title;
            e.StartDate = data.StartDate;
            e.EndDate = data.EndDate;
            e.IsCurrent = data.IsCurrent;
            e.Description = data.Description;
