@page "/apply"
@rendermode InteractiveServer

@using sv_c1b04053b23b4f3d92d1b7ce0747b936.Components.Pages.Application
@using sv_c1b04053b23b4f3d92d1b7ce0747b936.Models

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep FullName="@personalFullName"
                              Email="@personalEmail"
                              Phone="@personalPhone"
                              Address="@personalAddress"
                              OnNext="HandlePersonalNext" />
            break;

        case 1:
            <WorkHistoryStep InitialEntries="workEntries"
                             OnNext="HandleWorkNext"
                             OnBack="() => GoToStep(0)" />
            break;

        case 2:
            <ReferencesStep InitialReferences="referenceEntries"
                            OnNext="HandleReferencesNext"
                            OnBack="() => GoToStep(1)" />
            break;

        case 3:
            <CoverLetterStep CoverLetter="@coverLetter"
                             OnNext="HandleCoverLetterNext"
                             OnBack="() => GoToStep(2)" />
            break;

        case 4:
            <ReviewStep Personal="@savedPersonal"
                        WorkEntries="@savedWorkEntries"
                        References="@savedReferences"
                        CoverLetter="@coverLetter"
                        OnEditStep="GoToStep"
                        OnBack="() => GoToStep(3)" />
            break;
    }
</div>

@code {
    private int currentStep;
    private HashSet<int> completedSteps = new();

    // Personal info state
    private string personalFullName = "";
    private string personalEmail = "";
    private string personalPhone = "";
    private string personalAddress = "";
    private PersonalInfo? savedPersonal;

    // Work history state
    private List<WorkHistoryStep.WorkEntryModel>? workEntries;
    private List<WorkEntry>? savedWorkEntries;

    // References state
    private List<ReferencesStep.ReferenceModel>? referenceEntries;
    private List<Reference>? savedReferences;

    // Cover letter state
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private void HandlePersonalNext(PersonalInfo info)
    {
        savedPersonal = info;
        personalFullName = info.FullName;
        personalEmail = info.Email;
        personalPhone = info.Phone;
        personalAddress = info.Address;
        completedSteps.Add(0);
        currentStep = 1;
    }

    private void HandleWorkNext(List<WorkHistoryStep.WorkEntryModel> entries)
    {
        workEntries = entries;
        savedWorkEntries = entries.Select(e => new WorkEntry(
            e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description
        )).ToList();
        completedSteps.Add(1);
        currentStep = 2;
    }

    private void HandleReferencesNext(List<ReferencesStep.ReferenceModel> refs)
    {
        referenceEntries = refs;
        savedReferences = refs.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList();
        completedSteps.Add(2);
        currentStep = 3;
    }

    private void HandleCoverLetterNext(string letter)
    {
        coverLetter = letter;
        completedSteps.Add(3);
        currentStep = 4;
    }
}

