@using sv_c1b04053b23b4f3d92d1b7ce0747b936.Models

<div class="card p-4">
    <h4 class="mb-3">Work History</h4>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var idx = i;
        var e = Entries[idx];
        <WorkEntryForm Index="idx"
                       Company="@e.Company"
                       Title="@e.Title"
                       StartDate="@e.StartDate"
                       EndDate="@e.EndDate"
                       IsCurrent="@e.IsCurrent"
                       Description="@e.Description"
                       CanRemove="@(Entries.Count > 1)"
                       Attempted="@Attempted"
                       OnRemove="() => RemoveEntry(idx)"
                       OnChanged="(data) => UpdateEntry(idx, data)" />
    }

    <button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        + Add Another Position
    </button>

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public List<WorkEntryModel>? InitialEntries { get; set; }
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryModel>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private List<WorkEntryModel> Entries = new();
    private bool Attempted;

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    protected override void OnInitialized()
    {
        if (InitialEntries is { Count: > 0 })
        {
            Entries = InitialEntries.Select(e => new WorkEntryModel
            {
                Company = e.Company,
                Title = e.Title,
                StartDate = e.StartDate,
                EndDate = e.EndDate,
                IsCurrent = e.IsCurrent,
                Description = e.Description
            }).ToList();
        }
        else
        {
            Entries.Add(new WorkEntryModel());
        }
    }

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private void UpdateEntry(int index, WorkEntryForm.WorkEntryData data)
    {
        if (index < Entries.Count)
        {
            var e = Entries[index];
            e.Company = data.Company;
            e.Title = data.Title;
            e.StartDate = data.StartDate;
            e.EndDate = data.EndDate;
            e.IsCurrent = data.IsCurrent;
            e.Description = data.Description;
        }
    }

    private async Task HandleNext()
    {
        Attempted = true;

        foreach (var e in Entries)
        {
            if (string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title)
                || e.StartDate == default || string.IsNullOrWhiteSpace(e.Description))
            {
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }
}

